parameters.jsCode:
// Get the text content
const textContent = $input.first().json.content.parts[0].text;

// Remove the ```json and ``` markdown code fences
const cleanedText = textContent.replace(/```json\n?|\n?```/g, '').trim();

// Parse the JSON
const parsedData = JSON.parse(cleanedText);

// Return the parsed data
return {
  json: parsedData
};

